import * as React from 'react';
import { useFirstMountState } from '../hooks/useFirstMountState';

export const _log = <T extends (...args: any[]) => any>(fn: T): T =>
  ((...args: Parameters<T>[]) => {
    console.trace(fn.name, 'args:', ...args);
    return fn(...args);
  }) as ReturnType<T>;

export const useRenderedReason = (name: string, depsMap: Record<string, any>) => {
  const isFirstMount = useFirstMountState();
  const changedKeysRef = React.useRef(new Set<string>());
  React.useEffect(() => {
    changedKeysRef.current = new Set();
  });
  for (const [k, v] of Object.entries(depsMap)) {
    // eslint-disable-next-line react-hooks/rules-of-hooks
    React.useEffect(() => {
      changedKeysRef.current.add(k);
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [v]);
  }
  React.useEffect(() => {
    if (changedKeysRef.current.size && !isFirstMount) {
      console.log(`${name} rendered: deps ${[...changedKeysRef.current].map(o => `\`${o}\``).join(', ')} changed`);
    }
  });
};
